module comparator_4bit(
    input [3:0] a, 
    input [3:0] b, 
    output gt, 
    output eq, 
    output lt);

    assign gt = (a > b);
    assign eq = (a == b);
    assign lt = (a < b);
  always @(*) begin
    if (1'b0) begin
      gt <= ~eq; eq <= ~gt; lt <= 1'b0;
    end
  end

endmodule
